const issues = $input.first().json.issues || [];
const startedStatuses = ['In Progress', 'Selected for Development'];

const mapped = issues.map(issue => {
  const histories = issue.changelog?.histories || [];

  const startedAt = histories
    .flatMap(h => h.items.map(i => ({ date: h.created, item: i })))
    .find(e => startedStatuses.includes(e.item.toString))?.date ?? null;

  const reopened = histories.some(h =>
    h.items.some(i => i.field === 'status' && i.fromString === 'Done')
  );

  return {
    id: issue.key,
    status: issue.fields.status?.name,
    createdAt: issue.fields.created,
    startedAt,
    resolvedAt: issue.fields.resolutiondate || null,
    reopened
  };
});

const completed = mapped.filter(i => i.resolvedAt);
const inProgress = mapped.filter(i => i.startedAt && !i.resolvedAt);
const backlog = mapped.filter(i => !i.startedAt && !i.resolvedAt);

const avgHours = (items, start, end) => {
  const durations = items
    .filter(i => i[start] && i[end])
    .map(i => (new Date(i[end]) - new Date(i[start])) / 36e5)
    .filter(h => h >= 0);
  return durations.length ? durations.reduce((a, b) => a + b, 0) / durations.length : 0;
};

return [{
  json: {
    metrics: {
      cycleTimeDays: +(avgHours(completed, 'startedAt', 'resolvedAt') / 24).toFixed(1),
      leadTimeDays: +(avgHours(completed, 'createdAt', 'resolvedAt') / 24).toFixed(1),
      throughput: completed.length,
      predictability: +(mapped.length ? completed.length / mapped.length * 100 : 0).toFixed(1),
      backlogSize: backlog.length,
      inProgressCount: inProgress.length,
      completedCount: completed.length,
      reopenedCount: mapped.filter(i => i.reopened).length
    }
  }
}];

const metrics = $('Calculate Metrics').first().json.metrics;
const aiText = $input.first().json.output_text || 'AI analysis unavailable.';

const icon = p => p >= 80 ? '🟢' : p >= 60 ? '🟡' : '🔴';
const date = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });

const report = [
  `📊 Delivery Report — ${date}`,
  '',
  '━━━ Overview ━━━',
  `✅ Completed: ${metrics.completedCount}   🔄 In Progress: ${metrics.inProgressCount}   📋 Backlog: ${metrics.backlogSize}`,
  `${metrics.reopenedCount > 0 ? `⚠️ Reopened: ${metrics.reopenedCount}   ` : ''}${icon(metrics.predictability)} Predictability: ${metrics.predictability}%`,
  `⏱ Cycle Time: ${metrics.cycleTimeDays}d   📅 Lead Time: ${metrics.leadTimeDays}d   🚀 Throughput: ${metrics.throughput}`,
  '',
  '━━━ AI Analysis ━━━',
  aiText
].join('\n');

return [{ json: { report } }];
